#!/usr/bin/env node
const fs=require("fs"),path=require("path"),filePath=path.join(__dirname,"..","index.html"),buf=fs.readFileSync(filePath),asUtf8=buf.toString("utf8"),fixedBuf=Buffer.from(asUtf8,"latin1"),fixed=fixedBuf.toString("utf8");if(fixed.includes("yhdessä paikassa")&&fixed.includes("Löydä")){fs.writeFileSync(filePath,fixedBuf),console.log("✅ Encoding fixed and file written successfully!");["yhdessä","Löydä","Tiedä","Päätösten","Elämykset"].forEach(e=>console.log("  ✓",fixed.includes(e)?e+" OK":e+" NOT FOUND"))}else console.log("⚠️ Sanity check failed. Sample:",JSON.stringify(fixed.slice(fixed.indexOf("yhdess"),fixed.indexOf("yhdess")+30)));